import { type TouchList as ReactTouchList } from 'react';

import type { Point } from './point.js';
export const enum PointerEventActions {
  Idle = 'idle',
  Hover = 'hover',
  Click = 'click',
  DblClick = 'dbl-click',
  Tap = 'tap',
  DblTap = 'dbl-tap',
  DragStart = 'drag:start',
  DragMove = 'drag:move',
  DragEnd = 'drag:end',
  PinchStart = 'pinch:start',
  Pinch = 'pinch',
  PinchEnd = 'pinch:end',
  SwipeStart = 'swipe:start',
  SwipeMove = 'swipe:move',
  SwipeEnd = 'swipe:end',
  MiddleButtonDragStart = 'middle-button-drag:start',
  MiddleButtonDragMove = 'middle-button-drag:move',
  MiddleButtonDragEnd = 'middle-button-drag:end',
}

/**
 * @internal
 */
export interface RelativeAbsolutePosition {
  relative: Point;
  absolute: Point;
}

export interface Idle {
  action: PointerEventActions.Idle;
}

export interface PointerEventModifiers {
  altKey: boolean;
  ctrlKey: boolean;
  metaKey: boolean;
  shiftKey: boolean;
}

export type PointerEventsHandler<T> = (
  event: PointerEventModifiers & T,
) => void;

export interface PinchStartProps {
  distance: number;
}

export interface PinchEndProps {
  changeRatio: number;
  distance: number;
  delta: number;
}

export interface SwipeStartProps {
  position: ReactTouchList;
}

export type SwipeDirections = 'left' | 'right' | 'up' | 'down';

export interface SwipeMoveProps extends SwipeStartProps {
  delta: number;
  direction: SwipeDirections;
  deltaX: number;
  deltaY: number;
}

export type SwipeEndProps = SwipeMoveProps;

export interface SwipeStart extends SwipeStartProps {
  action: PointerEventActions.SwipeStart;
}

export interface SwipeMove extends SwipeMoveProps {
  action: PointerEventActions.SwipeMove;
}

export interface SwipeEnd extends SwipeEndProps {
  action: PointerEventActions.SwipeEnd;
}

export interface PinchMoveProps extends PinchEndProps {
  initialDistance: number;
}

export interface PinchStart extends PinchStartProps {
  action: PointerEventActions.PinchStart;
}

export interface PinchMove extends PinchMoveProps {
  action: PointerEventActions.Pinch;
}

export interface PinchEnd extends PinchEndProps {
  action: PointerEventActions.PinchEnd;
}

export interface DragStartProps {
  startHoldingAt: RelativeAbsolutePosition;
}

export interface DragMoveProps extends DragStartProps {
  currentPosition: RelativeAbsolutePosition;
  delta: number;
}

export interface DragEndProps extends DragStartProps {
  releasedAt: RelativeAbsolutePosition;
}

export interface PointerEventPosition {
  position: RelativeAbsolutePosition;
}

export interface DragMove extends DragMoveProps {
  action: PointerEventActions.DragMove;
}

export interface DragStart extends DragStartProps {
  action: PointerEventActions.DragStart;
}

export interface DragEnd extends DragEndProps {
  action: PointerEventActions.DragEnd;
}

export interface Hover extends PointerEventPosition {
  action: 'hover';
}

export interface Click extends PointerEventPosition {
  action: PointerEventActions.Click;
}

export interface DblClick extends PointerEventPosition {
  action: PointerEventActions.DblClick;
}

export interface Tap extends PointerEventPosition {
  action: PointerEventActions.Tap;
}

export interface DblTap extends PointerEventPosition {
  action: PointerEventActions.DblTap;
}

export interface MiddleButtonDragStart extends DragStartProps {
  action: PointerEventActions.MiddleButtonDragStart;
}

export interface MiddleButtonDragMove extends DragMoveProps {
  action: PointerEventActions.MiddleButtonDragMove;
}

export interface MiddleButtonDragEnd extends DragEndProps {
  action: PointerEventActions.MiddleButtonDragEnd;
}

export type PointerEvents =
  | Idle
  | Hover
  | PinchStart
  | PinchMove
  | PinchEnd
  | DragStart
  | DragMove
  | DragEnd
  | SwipeStart
  | SwipeMove
  | SwipeEnd
  | Click
  | DblClick
  | Tap
  | DblTap
  | MiddleButtonDragStart
  | MiddleButtonDragMove
  | MiddleButtonDragEnd;

export const isDragMove = (gesture?: PointerEvents): gesture is DragMove =>
  gesture?.action === PointerEventActions.DragMove;

export const isMiddleButtonDragMove = (
  gesture?: PointerEvents,
): gesture is MiddleButtonDragMove =>
  gesture?.action === PointerEventActions.MiddleButtonDragMove;

export const isPinchGesture = (gesture?: PointerEvents): gesture is PinchMove =>
  gesture?.action === PointerEventActions.Pinch;

export const isPinchStartGesture = (
  gesture?: PointerEvents,
): gesture is PinchStart => gesture?.action === PointerEventActions.PinchStart;

export const isSwipeStart = (gesture?: PointerEvents): gesture is SwipeStart =>
  gesture?.action === PointerEventActions.SwipeStart;

export const isSwipeMove = (gesture?: PointerEvents): gesture is SwipeMove =>
  gesture?.action === PointerEventActions.SwipeMove;

export type ViewportEventPosition = {
  clientX: number;
  clientY: number;
};
